{"code": "from hermes_tools import terminal, read_file, search_files
import json

def scan_repo(path, name):
    result = {
        "name": name,
        "pages": [],
        "components": [],
        "lib_files": [],
        "content_files": [],
        "models_types": [],
        "hooks": [],
        "styles": [],
        "layouts": [],
        "server_actions": [],
        "api_routes": [],
        "data_imports": [],
        "forms": [],
        "features": set()
    }

    # Scan pages/routes
    for app_path in ["app", "pages", "src/app", "src/pages"]:
        full = f"{path}/{app_path}"
        t = terminal(f"find {full} -maxdepth 3 -type f -name 'page.*' -o -name 'layout.*' -o -name 'route.*' -o -name 'loading.*' -o -name 'error.*' 2>/dev/null | head -50", timeout=10)
        for f in t['output'].strip().split('\n'):
            if f:
                rel = f.replace(full+'/', '')
                result['pages'].append(rel)

        # layouts
        t2 = terminal(f"find {full} -maxdepth 2 -name 'layout.*' 2>/dev/null | head -10", timeout=10)
        for f in t2['output'].strip().split('\n'):
            if f:
                result['layouts'].append(f.replace(full+'/', ''))

    # Scan components
    for comp_path in ["components", "src/components"]:
        full = f"{path}/{comp_path}"
        t = terminal(f"find {full} -type f -name '*.tsx' -o -name '*.jsx' -o -name '*.ts' 2>/dev/null | head -50", timeout=10)
        for f in t['output'].strip().split('\n'):
            if f:
                result['components'].append(f.replace(full+'/', ''))

    # Scan lib
    for lib_path in ["lib", "src/lib", "utils"]:
        full = f"{path}/{lib_path}"
        t = terminal(f"find {full} -type f -name '*.ts' -o -name '*.tsx' -o -name '*.js' 2>/dev/null | head -30", timeout=10)
        for f in t['output'].strip().split('\n'):
            if f:
                result['lib_files'].append(f.replace(full+'/', ''))

    # Scan content
    for cont_path in ["content", "data", "src/content", "src/data"]:
        full = f"{path}/{cont_path}"
        t = terminal(f"find {full} -type f 2>/dev/null | head -30", timeout=10)
        for f in t['output'].strip().split('\n'):
            if f:
                result['content_files'].append(f.replace(full+'/', ''))

    # Scanner for data models and types
    for type_path in ["types", "src/types", "models", "src/models", "@types"]:
        full = f"{path}/{type_path}"
        t = terminal(f"find {full} -type f 2>/dev/null | head -20", timeout=10)
        for f in t['output'].strip().split('\n'):
            if f:
                result['models_types'].append(f.replace(full+'/', ''))

    return result

repos = {
    "superspuma": "/root/superspuma",
    "golden-visa": "/root/golden-visa-advisory",
    "elviajero": "/root/elviajero-comercio",
    "dayah": "/root/dayah-litworks-deploy",
    "fun4me": "/root/fun4me-store",
    "nudo": "/root/nudo/repo",
    "ozmontania": "/root/ozmontania-website",
    "duerksen": "/root/clinica-duerksen",
    "granja-cabral": "/root/granja-cabral",
    "3md": "/root/3md-website",
    "stroopwafel": "/root/stroopwafel-huis",
    "nicolas-duarte": "/root/repos/nicolas-duarte-site"
}

for name, path in repos.items():
    r = scan_repo(path, name)
    print(f"\n{'='*70}")
    print(f"📁 {name} ({path})")
    print(f"   Pages: {len(r['pages'])}")
    for p in r['pages'][:15]:
        print(f"   - {p}")
    print(f"   Components: {len(r['components'])}")
    for c in sorted(r['components'])[:12]:
        print(f"   - {c}")
    print(f"   Lib: {len(r['lib_files'])}")
    for l in r['lib_files'][:8]:
        print(f"   - {l}")
    print(f"   Content: {len(r['content_files'])}")
    for ct in r['content_files'][:6]:
        print(f"   - {ct}")
    print(f"   Layouts: {r['layouts'][:3]}")
"}

